SELECT s.id, s.salary_no AS salaryNo, s.user_id AS userId, s.dept_id AS deptId, s.salary_month AS yearMonth, s.status, s.base_salary AS baseSalary, s.position_salary AS positionSalary, s.performance_salary AS performanceSalary, s.overtime_salary AS overtimeSalary, s.bonus, s.subsidy, s.other_addition AS otherAddition, s.social_insurance AS socialInsurance, s.personal_tax AS personalTax, s.late_fine AS lateFine, s.other_deduction AS otherDeduction, s.gross_salary AS grossSalary, s.net_salary AS netSalary, s.creator_id AS creatorId, s.create_time AS createTime FROM oa_salary s WHERE 1=1
AND s.salary_month = #{yearMonth}
AND s.status = #{status}
AND s.dept_id = #{deptId}
ORDER BY s.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM oa_salary s
WHERE 1=1

    AND s.salary_month = #{yearMonth}


    AND s.status = #{status}


    AND s.dept_id = #{deptId}

SELECT s.id, s.salary_no AS salaryNo, s.user_id AS userId, s.dept_id AS deptId, s.salary_month AS yearMonth, s.status, s.base_salary AS baseSalary, s.position_salary AS positionSalary, s.performance_salary AS performanceSalary, s.overtime_salary AS overtimeSalary, s.bonus, s.subsidy, s.other_addition AS otherAddition, s.social_insurance AS socialInsurance, s.personal_tax AS personalTax, s.late_fine AS lateFine, s.other_deduction AS otherDeduction, s.gross_salary AS grossSalary, s.net_salary AS netSalary, s.create_time AS createTime FROM oa_salary s WHERE s.user_id = #{userId}
AND s.salary_month >= #{startMonth}
AND s.salary_month <= #{endMonth}
ORDER BY s.salary_month DESC

SELECT s.id, s.salary_no AS salaryNo, s.user_id AS userId, s.dept_id AS deptId, s.salary_month AS yearMonth, s.status, s.base_salary AS baseSalary, s.position_salary AS positionSalary, s.performance_salary AS performanceSalary, s.overtime_salary AS overtimeSalary, s.bonus, s.subsidy, s.other_addition AS otherAddition, s.social_insurance AS socialInsurance, s.personal_tax AS personalTax, s.late_fine AS lateFine, s.other_deduction AS otherDeduction, s.gross_salary AS grossSalary, s.net_salary AS netSalary, s.create_time AS createTime FROM oa_salary s WHERE s.salary_month = #{yearMonth}
AND s.dept_id = #{deptId}
ORDER BY s.dept_id, s.user_id
